226	    let secrets_dir = rbtdrk_read_env_value(&rbrr, RBTDRK_FIELD_RBRR_SECRETS_DIR)
227	        .ok_or_else(|| format!("RBRR_SECRETS_DIR missing from {}", rbrr.display()))?;
228	    if secrets_dir.is_empty() {
229	        return Err(format!("RBRR_SECRETS_DIR is blank in {}", rbrr.display()));
230	    }
231	    Ok(rbtdrk_resolve(root, &secrets_dir)
232	        .join(role)
233	        .join(RBTDGC_RBRA_FILE))
234	}
