769	/// Shared invest body for retriever and director: invest → assert assay
770	/// dropped by the invest tabtarget → copy to canonical role path → access-probe.
771	fn rbtdrk_role_invest_impl(
772	    ctx: &mut rbtdri_Context,
773	    dir: &Path,
774	    invest_colophon: &str,
775	    identity: &str,
776	    role: &str,
777	) -> rbtdre_Verdict {
778	    let root = ctx.project_root().to_path_buf();
779	
780	    let assay = match rbtdrk_canonical_rbra(&root, RBTDGC_ACCOUNT_ASSAY) {
781	        Ok(p) => p,
782	        Err(e) => return rbtdre_Verdict::Fail(format!("canonical assay RBRA path: {}", e)),
783	    };
784	
785	    // Invest is idempotent (RBSRK/RBSDK): a standing-depot rerun rotates the key
786	    // on the existing SA; a freshly-levied depot creates it. Either way the invest
787	    // tabtarget drops the assay RBRA.
788	
789	    let label_invest = format!("invest-{}", role);
790	    let invest = match rbtdrk_invoke_logged(
791	        ctx,
792	        invest_colophon,
793	        &[identity],
794	        &[],
795	        dir,
796	        &label_invest,
797	    ) {
798	        Ok(r) => r,
799	        Err(e) => return rbtdre_Verdict::Fail(format!("invest {}: {}", role, e)),
800	    };
801	    if invest.exit_code != 0 {
802	        return rbtdre_Verdict::Fail(format!(
803	            "invest {} exit {}\n{}",
804	            role, invest.exit_code, invest.stderr
805	        ));
806	    }
807	
808	    if !assay.exists() {
809	        return rbtdre_Verdict::Fail(format!(
810	            "assay RBRA absent after invest-{}: {}",
811	            role,
812	            assay.display()
813	        ));
814	    }
815	
816	    let canonical = match rbtdrk_canonical_rbra(&root, role) {
817	        Ok(p) => p,
818	        Err(e) => return rbtdre_Verdict::Fail(format!("canonical {} RBRA path: {}", role, e)),
819	    };
820	    if let Some(parent) = canonical.parent() {
821	        if let Err(e) = std::fs::create_dir_all(parent) {
822	            return rbtdre_Verdict::Fail(format!(
823	                "create {} RBRA dir {}: {}",
824	                role,
825	                parent.display(),
826	                e
827	            ));
828	        }
829	    }
830	    if let Err(e) = std::fs::copy(&assay, &canonical) {
831	        return rbtdre_Verdict::Fail(format!(
832	            "copy assay RBRA → {} canonical {}: {}",
833	            role,
834	            canonical.display(),
835	            e
836	        ));
837	    }
838	
839	    let probe_colophon = match rbtdrm_credential_check_colophon(role) {
840	        Some(c) => c,
841	        None => return rbtdre_Verdict::Fail(format!("unknown credential role: {}", role)),
842	    };
843	    let probe_result = match rbtdri_invoke_global(ctx, probe_colophon, &[], &[]) {
844	        Ok(r) => r,
845	        Err(e) => {
846	            return rbtdre_Verdict::Fail(format!("access-probe {} invocation: {}", role, e))
847	        }
848	    };
849	    let _ = std::fs::write(
850	        dir.join(format!("probe-{}-stdout.txt", role)),
851	        &probe_result.stdout,
852	    );
853	    let _ = std::fs::write(
854	        dir.join(format!("probe-{}-stderr.txt", role)),
855	        &probe_result.stderr,
856	    );
857	    if probe_result.exit_code != 0 {
858	        return rbtdre_Verdict::Fail(format!(
859	            "access-probe {} exit {}\n{}",
860	            role, probe_result.exit_code, probe_result.stderr
861	        ));
862	    }
863	
864	    rbtdre_Verdict::Pass
865	}
866	
867	// ── Section registry ─────────────────────────────────────────
868	
869	pub static RBTDRK_CASES_CANONICAL_ESTABLISH: &[rbtdre_Case] = &[
870	    case!(rbtdrk_depot_levy),
871	    case!(rbtdrk_governor_mantle),
872	    case!(rbtdrk_retriever_invest),
873	    case!(rbtdrk_director_invest),
874	];
875	
876	pub static RBTDRK_FIXTURE_CANONICAL_ESTABLISH: rbtdre_Fixture = rbtdre_Fixture {
877	    name: RBTDRM_FIXTURE_CANONICAL_ESTABLISH,
878	    disposition: rbtdre_Disposition::StateProgressing,
879	    setup: None,
880	    teardown: None,
881	    cases: RBTDRK_CASES_CANONICAL_ESTABLISH,
882	};
883	
884	// canonical-invest — the no-levy recycle variant shared by skirmish, dogfight,
885	// and blockade. Runs against a depot the operator has levied by hand (no GCP
886	// project created per run). After re-mantling the governor it divests then
887	// re-invests retriever + director, so every run exercises the full teardown →
888	// reinvest cycle: rbgg_divest_*'s revoke-before-delete and poll_until_gone
889	// debounce, then the invest create branch against a durably-gone SA. This
890	// deliberately stresses the IAM eventual-consistency edges (the delete→recreate
891	// read-flap) on every run. Each case carries its own precondition probe
892	// (governor mantle probes the standing depot's moniker; divest/invest probe the
893	// governor). Divest runs in reverse role order, invest in forward order. Sharing
894	// the case fns is the same provenance-vs-behavior split tadmor/moriah exploit
895	// with RBTDRC_CASES_SECURITY.
896	pub static RBTDRK_CASES_CANONICAL_INVEST: &[rbtdre_Case] = &[
897	    case!(rbtdrk_governor_mantle),
898	    case!(rbtdrk_director_divest),
899	    case!(rbtdrk_retriever_divest),
900	    case!(rbtdrk_retriever_invest),
901	    case!(rbtdrk_director_invest),
902	];
903	
904	pub static RBTDRK_FIXTURE_CANONICAL_INVEST: rbtdre_Fixture = rbtdre_Fixture {
905	    name: RBTDRM_FIXTURE_CANONICAL_INVEST,
906	    disposition: rbtdre_Disposition::StateProgressing,
907	    setup: None,
908	    teardown: None,
909	    cases: RBTDRK_CASES_CANONICAL_INVEST,
910	};
911

